def solve(age, gender, body_weight_kg, measured_sodium_mmol_per_l):
    # Step 1: total_body_water_fraction_selection
    # Determine the total body water fraction based on the patient's age and gender.
    if gender == 'male':
        if age <= 65:
            tbw_fraction = 0.6
        else:
            tbw_fraction = 0.5
    elif gender == 'female':
        if age <= 65:
            tbw_fraction = 0.5
        else:
            tbw_fraction = 0.45
    else:
        raise ValueError("gender must be 'male' or 'female'")

    yield {
        "step_name": "total_body_water_fraction_selection",
        "step_description": "Determine the total body water fraction based on the patient's age and gender.",
        "step_result": tbw_fraction,
        "unit": None
    }

    # Step 2: free_water_deficit_calculation
    # Calculate the free water deficit in liters using the formula:
    # free_water_deficit_l = tbw_fraction * body_weight_kg * (measured_sodium_mmol_per_l / 140 - 1)
    # Round the result to 4 decimal places.
    free_water_deficit_l = round(tbw_fraction * body_weight_kg * (measured_sodium_mmol_per_l / 140 - 1), 4)

    yield {
        "step_name": "free_water_deficit_calculation",
        "step_description": "Calculate the free water deficit in liters using the formula: (total body water fraction) * (body weight in kg) * (measured sodium concentration / 140 - 1).",
        "step_result": free_water_deficit_l,
        "unit": "liters"
    }

    # Final output
    return free_water_deficit_l
